const data = $('LINEメッセージ解析').first().json;
const claudeResponse = $input.first().json;

try {
  const textContent = claudeResponse.content[0].text;
  const jsonMatch = textContent.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('Claude応答のJSON抽出失敗');

  const parsed = JSON.parse(jsonMatch[0]);
  if (!parsed.date || !parsed.sites || parsed.sites.length === 0) {
    throw new Error('日付または現場情報が取得できませんでした');
  }

  // 稼働時間を計算
  for (const site of parsed.sites) {
    if (site.startTime && site.endTime) {
      const [sh, sm] = site.startTime.split(':').map(Number);
      const [eh, em] = site.endTime.split(':').map(Number);
      let totalMin = (eh * 60 + em) - (sh * 60 + sm);
      if (totalMin < 0) totalMin += 24 * 60;
      totalMin -= (site.breakMin || 0);
      const h = Math.floor(totalMin / 60);
      const m = totalMin % 60;
      site.workingTime = `${h}:${String(m).padStart(2, '0')}`;
    }
    site.highwayFee   = parseInt(site.highwayFee)  || 0;
    site.distance     = parseInt(site.distance)     || 0;
    site.parkingFee   = parseInt(site.parkingFee)   || 0;
    site.materialFee  = parseInt(site.materialFee)  || 0;
    site.breakMin     = parseInt(site.breakMin)     || 0;
  }

  return [{ json: { ...data, parsedDate: parsed.date, sites: parsed.sites, valid: true } }];

} catch (e) {
  return [{ json: {
    valid: false,
    replyToken: data.replyToken,
    errorMessage: `日報の解析に失敗しました。\n以下を確認してください：\n・日付が正しいか（例：2026/04/18）\n・区分が正しいか（昼勤 / 夜勤）\n・すでに送信済みでないか`
  }}];
}

const ExcelJS = require('exceljs');

return await (async () => {
  const data     = $('Claude解析結果処理').first().json;
  const fileInfo = $('ファイル情報取得').first().json;

  try {
    const workbook = new ExcelJS.Workbook();
    const buffer   = await this.helpers.getBinaryDataBuffer(0, 'data');

    if (!buffer || buffer.length === 0) {
      throw new Error('Excelファイルのダウンロードに失敗しました');
    }

    await workbook.xlsx.load(buffer, { useSharedStrings: false });

    const MULTI_PERSON = ['梶原通信', 'LLS電気', '株式会社トラストテクノス', '株式会社RISE'];
    const isMulti = MULTI_PERSON.includes(data.employeeName);

    const sheet = workbook.getWorksheet(data.employeeName);
    if (!sheet) throw new Error(`シート「${data.employeeName}」が見つかりません`);

    const toDate = (str) => {
      if (!str) return null;
      const p = str.split('/');
      return new Date(Date.UTC(parseInt(p[0]), parseInt(p[1])-1, parseInt(p[2])));
    };

    const findOrCreateRow = () => {
      let target = null;
      sheet.eachRow((row, num) => {
        if (num < 2 || target) return;
        const cell = row.getCell(1).value;
        if (!cell) return;
        let rowDate = '';
        if (cell instanceof Date) {
          rowDate = `${cell.getUTCFullYear()}/${String(cell.getUTCMonth()+1).padStart(2,'0')}/${String(cell.getUTCDate()).padStart(2,'0')}`;
        } else {
          rowDate = String(cell).trim();
        }
        if (rowDate === data.parsedDate && !row.getCell(3).value) target = row;
      });
      if (!target) {
        const n = sheet.lastRow ? sheet.lastRow.number + 1 : 2;
        target = sheet.getRow(n);
        target.getCell(1).value  = toDate(data.parsedDate);
        target.getCell(1).numFmt = 'YYYY/MM/DD';
      }
      return target;
    };

    for (const site of data.sites) {
      const row = findOrCreateRow();
      row.getCell(2).value = site.companyName  || '';
      row.getCell(3).value = site.kubun        || '';
      row.getCell(4).value = site.propertyName || '';
      row.getCell(5).value = site.startTime    || '';
      row.getCell(6).value = site.endTime      || '';
      row.getCell(7).value = site.breakMin     || 0;
      row.getCell(8).value = site.workingTime  || '';
      row.getCell(9).value = site.workContent  || '';

      if (isMulti) {
        row.getCell(10).value = site.personnelCount || '';
        row.getCell(11).value = site.personnelNames || '';
        row.getCell(12).value = site.highwayFee;
        row.getCell(13).value = site.distance;
        row.getCell(14).value = site.parkingFee;
        row.getCell(15).value = site.materialFee;
      } else {
        row.getCell(10).value = site.highwayFee;
        row.getCell(11).value = site.distance;
        row.getCell(12).value = site.parkingFee;
        row.getCell(13).value = site.materialFee;
      }
    }

    const out = await workbook.xlsx.writeBuffer({ useSharedStrings: false });
    const bin = await this.helpers.prepareBinaryData(
      Buffer.from(out),
      data.fileName,
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    );

    return [{ json: { ...data, fileId: fileInfo.id, valid: true }, binary: { data: bin } }];

  } catch (err) {
    return [{ json: { valid: false, replyToken: data.replyToken, errorMessage: err.message } }];
  }
})();

const data  = $('Claude解析結果処理').first().json;
const sites = data.sites || [];

let msg = `✅ 日報を記録しました\n\n日付：${data.parsedDate}\n担当：${data.employeeName}`;

if (sites.length === 1) {
  const s = sites[0];
  msg += `\n\n会社名：${s.companyName}\n物件名：${s.propertyName}\n区分：${s.kubun}\n${s.startTime}〜${s.endTime}`;
  if (s.workingTime) msg += `（稼働 ${s.workingTime}）`;
  if (s.personnelNames) msg += `\n人員：${s.personnelNames}（${s.personnelCount}名）`;
  if (s.highwayFee)  msg += `\n高速：¥${s.highwayFee.toLocaleString('ja-JP')}`;
  if (s.distance)    msg += `\n距離：${s.distance}km`;
  if (s.parkingFee)  msg += `\n駐車場：¥${s.parkingFee.toLocaleString('ja-JP')}`;
  if (s.materialFee) msg += `\n資材費：¥${s.materialFee.toLocaleString('ja-JP')}`;
} else {
  sites.forEach((s, i) => {
    msg += `\n\n【現場${i+1}】\n${s.companyName}　${s.propertyName}\n${s.kubun}　${s.startTime}〜${s.endTime}`;
    if (s.personnelNames) msg += `\n人員：${s.personnelNames}（${s.personnelCount}名）`;
  });
}

return [{ json: { replyToken: data.replyToken, replyMessage: msg } }];
